// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  // Validate email format
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate step 1
  const isStep1Valid = (): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  // Validate step 2
  const isStep2Valid = (): boolean => {
    return formData.satisfaction > 0;
  };

  // Handle next button
  const handleNext = () => {
    if (currentStep === 1 && !isStep1Valid()) {
      return;
    }
    if (currentStep === 2 && !isStep2Valid()) {
      return;
    }
    setCurrentStep(currentStep + 1);
  };

  // Handle back button
  const handleBack = () => {
    setCurrentStep(currentStep - 1);
  };

  // Handle form input changes
  const handleNameChange = (value: string) => {
    setFormData({ ...formData, name: value });
    if (errors.name) setErrors({ ...errors, name: '' });
  };

  const handleEmailChange = (value: string) => {
    setFormData({ ...formData, email: value });
    if (errors.email) setErrors({ ...errors, email: '' });
  };

  const handleSatisfactionChange = (value: string) => {
    setFormData({ ...formData, satisfaction: parseInt(value, 10) });
  };

  const handleFeatureToggle = (feature: string) => {
    const newFeatures = formData.features.includes(feature)
      ? formData.features.filter((f) => f !== feature)
      : [...formData.features, feature];
    setFormData({ ...formData, features: newFeatures });
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setFormData({ ...formData, comments: value });
    }
  };

  // Handle submit
  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  // Determine if Next button should be disabled
  const isNextDisabled = () => {
    if (currentStep === 1) return !formData.name.trim() || !formData.email.trim() || !validateEmail(formData.email);
    if (currentStep === 2) return formData.satisfaction === 0;
    return false;
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Survey Form</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant)">Step {currentStep} of 5</Text>
        </Stack>
        <Divider margin="var(--ggui-spacing-2)" />

        {/* Progress Bar */}
        <Progress value={(currentStep / 5) * 100} max={100} size="md" />

        {/* Step 1: Personal Information */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name *"
                placeholder="Enter your full name"
                value={formData.name}
                onChange={handleNameChange}
                error={errors.name}
                required
              />
              <Input
                label="Email *"
                type="email"
                placeholder="your@email.com"
                value={formData.email}
                onChange={handleEmailChange}
                error={errors.email}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={formData.satisfaction.toString()}
                onChange={handleSatisfactionChange}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: (index + 1).toString(),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                placeholder="Share any additional feedback or comments..."
                value={formData.comments}
                onChange={handleCommentsChange}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                      <Text>{formData.name}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                      <Text>{formData.email}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                      <Text>{props.satisfactionLabels[formData.satisfaction - 1]}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Interested Features</Text>
                      <Text>{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                      <Text>{formData.comments || 'No comments provided'}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        <Spacer size={16} />
        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between" align="center">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled()}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

