      'lanthanide': 'var(--ggui-color-secondary-100)',
      'actinide': 'var(--ggui-color-secondary-200)',
    };
    return colorMap[category] || 'var(--ggui-color-surfaceVariant)';
  };

  const getCategoryTextColor = (category: string | undefined): string => {
    if (!category) return 'var(--ggui-color-onSurfaceVariant)';
    // Return darker text for most categories for contrast
    return 'var(--ggui-color-onSurface)';
  };

  return (
