          }}
        >
          {filteredElements.map((element) => {
            const isSelected = selectedElement?.symbol === element.symbol;
            const bgColor = getCategoryColor(element.category);
            const elementTextColor = getCategoryTextColor(element.category);
            const gridColumn = element.col || 1;
            const gridRow = element.row || 1;

            return (
              <Card
                key={element.symbol}
