                onClick={() => setSelectedElement(element)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                radius="md"
                style={{
                  gridColumn: gridColumn.toString(),
                  gridRow: gridRow.toString(),
                  background: isSelected
