                    }}
                  >
                    {selectedElement.category
                      ?.replace(/-/g, ' ')
                      .toUpperCase() || 'UNKNOWN'}
                  </Badge>
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}
        {/* No results message */}
        {filteredElements.length === 0 && (
          <Alert variant="info">
