/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Helper: render star rating
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    const stars = [];
    const clampedRating = Math.max(0, Math.min(5, rating));
    for (let i = 0; i < 5; i++) {
      const isFilled = i < Math.floor(clampedRating);
      stars.push(
        <Icon
          key={i}
          name="star"
          size={20}
          color={isFilled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      );
    }
    return stars;
  };

  // Helper: format price with currency
  const formatPrice = (price: number | undefined, currency: string | undefined): string => {
    if (!price) return 'N/A';
    const currencySymbol = currency === 'USD' ? '$' : currency === 'EUR' ? '€' : currency === 'GBP' ? '£' : currency || '';
    return `${currencySymbol}${price.toFixed(2)}`;
  };

  // Helper: get stock status
  const getStockStatus = (stock: number | undefined) => {
    if (!stock || stock === 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (stock < 10) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  };

  // Helper: handle add to cart
  const handleAddToCart = () => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  };

  // Helper: increment/decrement quantity
  const incrementQuantity = () => {
    const max = props.product.stock || 1;
    setQuantity((prev) => Math.min(prev + 1, max));
  };

  const decrementQuantity = () => {
    setQuantity((prev) => Math.max(prev - 1, 1));
  };

  const stockStatus = getStockStatus(props.product.stock);
  const isOutOfStock = stockStatus.variant === 'error';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock Status */}
        <Stack gap="var(--ggui-spacing-6)" direction="horizontal" align="start">
          {/* Product Image Placeholder */}
           <Box
             aria-label="Product image"
             background="var(--ggui-color-primary-100)"
             borderRadius="var(--ggui-shape-radius-lg)"
             padding="var(--ggui-spacing-12)"
             style={{ minWidth: '320px', minHeight: '320px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
           >
             <Stack align="center" gap="var(--ggui-spacing-4)">
               <Icon name="image" size={48} color="var(--ggui-color-primary-600)" />
               <Text variant="bodySmall" color="var(--ggui-color-primary-700)" align="center">
                 {props.product.name || 'Product Image'}
               </Text>
             </Stack>
           </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
            {/* Title */}
            <Heading level={2} color="var(--ggui-color-onSurface)">
              {props.product.name || 'Product Name'}
            </Heading>

            {/* Price */}
            <Heading level={3} color="var(--ggui-color-primary-600)">
              {formatPrice(props.product.price, props.product.currency)}
            </Heading>

            {/* Rating and Review Count */}
             <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-3)" aria-label={`Rating: ${props.product.rating || 0} out of 5 stars`}>
               <Row gap="var(--ggui-spacing-1)" align="center">
                 {renderStars(props.product.rating)}
               </Row>
               <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                 {props.product.rating || 0} ({props.product.reviewCount || 0} reviews)
               </Text>
             </Stack>

            {/* Stock Status Badge */}
            <Badge variant={stockStatus.variant} size="md">
              {stockStatus.label}
            </Badge>
          </Stack>
        </Stack>

        <Divider margin="var(--ggui-spacing-4)" />

        {/* MIDDLE SECTION: Tab Navigation */}
        <Tabs
          variant="line"
          size="md"
          activeKey={activeTab}
          onChange={setActiveTab}
          items={[
