            {typingActive && (
              <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typingSender} is typing</Text>
                <Spinner size={16} color="var(--ggui-color-primary-600)" />
              </Stack>
            )}
          </Row>
        </Card>

        {/* Message List */}
        <Card
          padding="var(--ggui-spacing-4)"
          shadow="sm"
          radius="lg"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-3)',
          }}
        >
          {allMessages.length === 0 ? (
            <Box
              padding="var(--ggui-spacing-6)"
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                minHeight: '200px',
              }}
            >
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </Box>
          ) : (
            allMessages.map((msg, index) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const showSenderName = index === 0 || allMessages[index - 1]?.sender !== msg.sender;

              return (
                <Stack
                  key={index}
                  gap="var(--ggui-spacing-1)"
                  align={isCurrentUser ? 'end' : 'start'}
                  style={{ maxWidth: '70%', alignSelf: isCurrentUser ? 'flex-end' : 'flex-start' }}
                >
                  {showSenderName && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                      {msg.sender}
                    </Text>
                  )}
                  <Box
                    padding="var(--ggui-spacing-3)"
                    background={
                      isCurrentUser
                        ? 'var(--ggui-color-primary-600)'
                        : 'var(--ggui-color-surfaceVariant)'
                    }
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{
                      wordBreak: 'break-word',
                      borderBottomLeftRadius: isCurrentUser ? 'var(--ggui-shape-radius-lg)' : '2px',
                      borderBottomRightRadius: isCurrentUser ? '2px' : 'var(--ggui-shape-radius-lg)',
                    }}
                  >
                    <Text
                      variant="body"
                      color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                    >
                      {msg.text}
                    </Text>
                  </Box>
                  {msg.timestamp && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                      {new Date(msg.timestamp).toLocaleTimeString([], {
                        hour: '2-digit',
                        minute: '2-digit',
                      })}
                    </Text>
                  )}
                </Stack>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Card>

        {/* Input Area */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Input
              label="Message"
              placeholder="Type your message..."
              value={inputValue}
              onChange={setInputValue}
              onKeyDown={handleKeyDown}
              style={{ flex: 1 }}
            />
            <Button
              variant="primary"
              onClick={handleSendMessage}
              disabled={!inputValue.trim()}
              rightIcon={<Icon name="send" size={16} />}
            >
              Send
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

