  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: merge initial stocks with live updates
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date | null>(null);

  // Apply price updates from stream to displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      setDisplayStocks((prevStocks) => {
        const updated = [...prevStocks];
        const index = updated.findIndex((s) => s.symbol === priceUpdate.latest?.symbol);
        if (index !== -1) {
          updated[index] = {
            ...updated[index],
            price: priceUpdate.latest.price ?? updated[index].price,
            change: priceUpdate.latest.change ?? updated[index].change,
            changePercent: priceUpdate.latest.changePercent ?? updated[index].changePercent,
          };
        }
        return updated;
      });
      setLastUpdatedTime(new Date());
    }
  }, [priceUpdate.latest]);

  // Format price with 2 decimals
  const formatPrice = (price?: number): string => {
    return price !== undefined ? `$${price.toFixed(2)}` : '-';
  };

  // Determine if change is positive or negative
  const isPositive = (change?: number): boolean => {
    return change !== undefined && change >= 0;
  };

  // Format change percent string
  const formatChangePercent = (percent?: number): string => {
    if (percent === undefined) return '-';
    const sign = percent >= 0 ? '+' : '';
    return `${sign}${percent.toFixed(2)}%`;
  };

  // Get color based on change
  const getChangeColor = (isPos: boolean): string => {
    return isPos ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Get border color based on change
  const getChangeBorderColor = (isPos: boolean): string => {
    return isPos ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  };

  // Get arrow character
  const getArrow = (isPos: boolean): string => {
    return isPos ? '▲' : '▼';
  };

  // Format last updated time
  const formatLastUpdated = (): string => {
    if (!lastUpdatedTime) return 'Never';
    const now = new Date();
    const diffMs = now.getTime() - lastUpdatedTime.getTime();
    const diffSecs = Math.floor(diffMs / 1000);
    if (diffSecs < 60) return `${diffSecs}s ago`;
    const diffMins = Math.floor(diffSecs / 60);
    if (diffMins < 60) return `${diffMins}m ago`;
    const diffHours = Math.floor(diffMins / 60);
    if (diffHours < 24) return `${diffHours}h ago`;
    return lastUpdatedTime.toLocaleTimeString();
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with title and last updated timestamp */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Market Watch</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {formatLastUpdated()}
          </Text>
        </Stack>

        {/* Stock cards grid - responsive: 3 cols on desktop, 1 on mobile */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-6)',
          }}
        >
          {displayStocks.map((stock, idx) => {
            const isPos = isPositive(stock.change);
            const changeColor = getChangeColor(isPos);
            const borderColor = getChangeBorderColor(isPos);
            const arrow = getArrow(isPos);
            const flashKey = `${stock.symbol}-${stock.price}-${idx}`;
            return (
              <Card
                key={stock.symbol || idx}
                padding="var(--ggui-spacing-6)"
                shadow="md"
                radius="lg"
                border={true}
                as={Hoverable}
                hoverStyle={{ opacity: 0.95 }}
                style={{
                  borderColor: borderColor,
                  transition: 'all 0.3s ease',
                }}
              >
                {/* Ticker and Company Name Row */}
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading
                    level={3}
                    color="var(--ggui-color-onSurface)"
                    style={{ fontWeight: 'var(--ggui-font-weight-bold)' }}
                  >
                    {stock.symbol || '-'}
                  </Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    {stock.name || '-'}
                  </Text>
                </Stack>

                {/* Price Display */}
                <div key={flashKey} style={{
                  fontSize: 'var(--ggui-font-size-2xl)',
                  fontWeight: 'var(--ggui-font-weight-bold)',
                  color: 'var(--ggui-color-onSurface)',
                }}>
                  {formatPrice(stock.price)}
                </div>

                {/* Change and Change Percent Row */}
                <Row gap="var(--ggui-spacing-3)" align="center">
                  <Text
                    variant="body"
                    color={changeColor}
                    style={{ fontWeight: 'var(--ggui-font-weight-semibold)' }}
                  >
                    {stock.change !== undefined ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2) : '-'}
                  </Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
                    <Text
                      variant="body"
                      color={changeColor}
                      style={{ fontWeight: 'var(--ggui-font-weight-semibold)' }}
                    >
                      {formatChangePercent(stock.changePercent)}
                    </Text>
                    <Text
                      variant="body"
                      color={changeColor}
                      style={{ fontSize: 'var(--ggui-font-size-lg)' }}
                    >
                      {arrow}
                    </Text>
                  </Stack>
                </Row>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

