                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Choose Avatar
                  <span style={{ color: 'var(--ggui-color-error-500)', marginLeft: '4px' }}>*</span>
                </Text>
                <Row gap="var(--ggui-spacing-3)" align="center">
                  {props.avatarOptions.map((emojiAvatar) => (
                    <Box
                      key={emojiAvatar}
                      as={Clickable}
                      onClick={() => setAvatar(emojiAvatar)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={avatar === emojiAvatar ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{
                        border: avatar === emojiAvatar ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                      }}
                    >
                      <Text size="3xl" align="center">{emojiAvatar}</Text>
                    </Box>
                  ))}                
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ width: '100%' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Preferences</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Customize your experience
              </Text>
              <Divider margin="var(--ggui-spacing-3)" />

              {/* Role Selection */}
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                placeholder="Select your role"
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Enable Email Notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
              />

              {/* Theme Preference */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Theme Preference
                </Text>
                <Row gap="var(--ggui-spacing-3)" align="center">
                  {['light', 'dark'].map((themeOption) => (
                    <Box
                      key={themeOption}
                      as={Clickable}
                      onClick={() => setTheme(themeOption)}
                      padding="var(--ggui-spacing-3)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={theme === themeOption ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{
                        border: theme === themeOption ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                        minWidth: '100px',
                        textAlign: 'center',
                      }}
                    >
                      <Text variant="label">{themeOption.charAt(0).toUpperCase() + themeOption.slice(1)}</Text>
                    </Box>
                  ))}                
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ width: '100%' }}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Profile</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please review your information before completing
              </Text>
              <Divider margin="var(--ggui-spacing-3)" />

              {/* Summary Section */}
              <Stack gap="var(--ggui-spacing-4)">
                {/* Profile Section */}
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text variant="label" weight="semibold">Profile Information</Text>
                    <Row gap="var(--ggui-spacing-4)" align="start">
                      <Text size="4xl">{avatar}</Text>
                      <Stack gap="var(--ggui-spacing-2)">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                          <Text variant="body">{name}</Text>
                        </Stack>
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                          <Text variant="body">{email}</Text>
                        </Stack>
                      </Stack>
                    </Row>
                  </Stack>
                </Box>

                {/* Preferences Section */}
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text variant="label" weight="semibold">Preferences</Text>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                        <Badge variant="primary">{role || 'Not selected'}</Badge>
                      </Row>
                      <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                        <Badge variant={emailNotifications ? 'success' : 'secondary'}>{emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                      </Row>
                      <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                        <Badge variant="primary">{theme.charAt(0).toUpperCase() + theme.slice(1)}</Badge>
                      </Row>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between" style={{ width: '100%' }}>
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
            {currentStep < 3 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!isStepValid()}
              >
                Next
              </Button>
            )}

            {currentStep === 3 && (
              <Button
                variant="primary"
                onClick={handleComplete}
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
    </Container>
  );
